e.actual_name as managerName,
cci.invoice_name
from t_shipper co
left join t_shipper_type cot on cot.shipper_id = co.shipper_id
left join t_shipper_invoice cci on cci.shipper_id = co.shipper_id
left join t_employee e on co.manager_id = e.employee_id
left join t_shipper_principal manager on co.shipper_id = manager.shipper_id

    left join t_shipper_principal sp on co.shipper_id = sp.shipper_id



